import React from 'react';
import Navbar from './Navbar';
import Footer from './Footer';

const Layout = ({ children }) => {
    return (
        <div>
            <Navbar />
            <main>{children}</main> {/* Le contenu dynamique de chaque page */}
            <Footer />
        </div>
    );
};

export default Layout;
